-- ── Oyster ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Oyster HR is a global employment platform that acts as an Employer of Record, letting companies hire, pay, and manage employees and contractors compliantly in more than 180 countries without setting up local entities.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 2 contractors); Employer of Record from $499-$699/employee/month$q$, starting_price),
  founded_year = COALESCE(2020, founded_year),
  company_size = COALESCE($q$501-1000 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States (fully distributed team)$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Oyster HR Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Oyster HR review 2026: Employer of Record pricing, global payroll, contractor management, and how it compares to Deel and Remote.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Oyster, operating as Oyster HR, is a global employment platform built around Employer of Record (EOR) services that let companies hire full-time employees and contractors in more than 180 countries without opening local legal entities. It was founded in January 2020 by Tony Jamous and Jack Mardack, is headquartered in San Francisco, and operates as a fully distributed, remote-first company with employees spread across roughly 70+ countries. Oyster has raised approximately $291 million in venture funding, most recently a Series D round, reaching a valuation of about $1.2 billion, and it achieved B Corp certification in 2023, a differentiator it markets alongside its focus on making global hiring more accessible for companies outside major tech hubs. The platform's product suite covers EOR employment, global payroll, contractor payments and management, US PEO services, and HR advisory (People Partner Services), plus tools like a misclassification risk analyzer and visa sponsorship support. Pricing is transparent and published rather than fully quote-gated: EOR pricing starts around $699 per employee per month (dropping to roughly $499 with annual billing), global contractor management starts at $29 per contractor per month after a free tier covering up to two contractors, global payroll is around $50 per user per month, US PEO is about $114 per employee per month, and dedicated HR advisory is billed at $300 per hour; a custom Scale plan exists for high-volume hiring. Pricing excludes gross salaries, statutory employer costs like social security and pensions, and foreign-exchange conversion charges, and Oyster typically requires roughly one month of gross salary as a deposit per employee. Target customers are startups, scale-ups, and remote-first companies expanding international headcount without the cost and delay of establishing foreign legal entities. Oyster's most frequently named competitors in the EOR and global payroll space are Deel, Remote, Papaya Global, and Rippling, with Deel and Remote in particular occupying similar market positioning around fast, self-serve global hiring for distributed teams.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '44ab8232-5537-40f1-b180-862658c8fcf5';

