-- ── Pabau ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Pabau is an all-in-one practice management platform for clinics, medical spas, and salons, combining online booking, patient records, payments, and marketing tools in a single subscription.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$Free (New Business plan); paid plans from GBP 50/month$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE($q$51-200 employees$q$, company_size),
  headquarters = COALESCE($q$Bedford, England, United Kingdom$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Pabau Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Pabau review 2026: pricing, booking, EMR, and marketing features for clinics and med spas, plus alternatives like Fresha and Jane.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Pabau is a practice management platform built for clinics, medical spas, aesthetics practices, physiotherapy clinics, and salons, combining online booking, electronic patient/client records, forms, payments, invoicing, marketing automation, inventory, and reporting into a single system. The company was founded in 2012 by CEO William Brandham and is headquartered in Bedford, England, with additional development operations reported in locations including Skopje, North Macedonia; it now serves a reported 3,500-plus practices across more than 40 countries. Pabau differentiates itself from single-purpose scheduling tools by offering full feature parity across every pricing tier, meaning even entry-level plans get the same clinical records, forms, payments, and marketing capabilities as higher tiers; the plans instead scale by number of users and clients rather than gated features. Pricing starts with a free New Business plan for a single user with fewer than 50 clients, followed by paid tiers named Starter/Solo (single user), Team (2-3 users), Medium (4-5 users), Group (6-15 users), and Enterprise (16-plus users, multi-location support), with the published Starter tier costing around GBP 50 per month and higher tiers requiring a sales conversation. Customers can save roughly 10-20% with annual billing, and optional paid add-ons called Marketing Plus, Care Plus, and Insight Plus extend functionality further. Target users are independent practitioners and multi-location clinic groups in medical aesthetics, dermatology, physiotherapy, wellness, and general practice who need a single platform rather than separate booking, EMR, and marketing tools. Pabau's most commonly cited competitors and alternatives include Fresha, Booksy, Jane App, Practice Better, and Carepatron, each targeting overlapping segments of the salon, spa, and clinical practice management market, with Pabau positioned toward more clinically oriented practices needing structured patient records alongside scheduling and payments.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'fcc0d22f-68b0-41c4-80f4-5ebf02a902a9';

