INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Can be more complex to configure than lighter-weight on-call tools for small teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$What is PagerDuty used for?$q$, $q$PagerDuty is used for on-call scheduling, real-time alerting, and automated incident response so engineering and IT operations teams can detect and resolve outages quickly.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$How much does PagerDuty cost?$q$, $q$PagerDuty offers a free plan for up to 5 users, a Professional plan at about $21/user/month, a Business plan at about $41/user/month (both billed annually), and custom Enterprise pricing.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Is PagerDuty publicly traded?$q$, $q$Yes, PagerDuty trades on the New York Stock Exchange under the ticker PD, having completed its IPO in April 2019.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Who founded PagerDuty?$q$, $q$PagerDuty was founded in 2009 by Alex Solomon, Andrew Miklas, and Baskar Puvanathasan.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Where is PagerDuty headquartered?$q$, $q$PagerDuty is headquartered in San Francisco, California, though it was originally founded in Toronto, Canada.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Does PagerDuty have a free plan?$q$, $q$Yes, PagerDuty's Free plan supports up to 5 users with on-call scheduling and unlimited API calls.$q$, 5, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$What are PagerDuty's main competitors?$q$, $q$Opsgenie (by Atlassian), Splunk On-Call (formerly VictorOps), and xMatters are commonly cited competitors and alternatives.$q$, 6, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Does PagerDuty use AI for incident management?$q$, $q$Yes, PagerDuty offers AI-driven features branded PagerDuty Advance for automated incident triage and event intelligence, available on paid tiers.$q$, 7, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Enterprise on-call and incident management$q$, $q$Large engineering organizations use PagerDuty to manage on-call rotations, escalate incidents, and coordinate response across hundreds of services.$q$, $q$Enterprise DevOps and SRE teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Small team alerting$q$, $q$Small engineering teams use PagerDuty's Free plan for basic on-call scheduling and alerting without upfront cost.$q$, $q$Startups and small engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Automated incident remediation$q$, $q$Organizations use runbook automation and AI-driven triage on Business/Enterprise plans to automatically resolve common incidents without manual intervention.$q$, $q$Platform and infrastructure teams at scale$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Free$q$, $q$Free$q$, $q$N/A (up to 5 users)$q$, NULL, $q$["1 on-call schedule","1 escalation policy","100 monthly phone/SMS notifications","650+ integrations","API access"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Professional$q$, $q$$21/user/month (annual) or $25/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Unlimited notifications and escalation policies","Basic chat experience (Slack, Teams)","External status page (250 subscribers)","SSO","1,000 AI Actions"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Business$q$, $q$$41/user/month (annual) or $49/user/month (monthly)$q$, $q$Monthly or annual$q$, NULL, $q$["Custom fields and incident types","Advanced ITSM integrations","Multi-year historical data","Internal status pages","5,000 AI Actions"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$Enterprise$q$, $q$Custom (contact sales)$q$, $q$Custom$q$, NULL, $q$["Advanced incident workflows","Runbook automation","Full chat with premium Slack actions","20,000 AI Actions","Dedicated customer success support"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$PagerDuty is a digital operations management platform that provides on-call scheduling, alerting, escalation policies, and automated incident response for engineering, DevOps, and IT operations teams. It is one of the most established, enterprise-trusted names in the incident management category.$q$, $q$Founded in 2009 by Alex Solomon, Andrew Miklas, and Baskar Puvanathasan and now headquartered in San Francisco, PagerDuty went public on the NYSE (ticker: PD) in April 2019. It reports usage by more than half of the Fortune 500.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include on-call scheduling, escalation policies, real-time alerting via SMS, phone, chat, and push notification, and more than 650-750 pre-built integrations across monitoring, ITSM, and chat tools such as Slack and Microsoft Teams.$q$, $q$Higher-tier plans add AI-driven capabilities branded PagerDuty Advance for automated incident triage and event intelligence, runbook automation to execute remediation steps automatically, custom incident roles and types, and both internal and external status pages.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('b183037a-4efe-4a36-bad0-06a1402afd4b', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$PagerDuty offers a Free plan for up to 5 users with basic on-call scheduling, unlimited API calls, and 650+ integrations. Paid plans are billed per user per month: Professional costs about $21/user/month (annual billing) and Business costs about $41/user/month (annual billing), each unlocking progressively more automation, ITSM integration, and administrative controls.$q$, $q$The top-tier Enterprise plan (formerly branded Digital Operations) is custom-priced and includes the deepest automation, event intelligence, and runbook automation capabilities, along with dedicated customer success support. Add-ons such as AIOps and status pages can increase total cost beyond the base per-user price.$q$]::text[], 2);
